"""
Web-based terminal with PTY support and xterm.js.
Run with: uvicorn main:app --host 127.0.0.1 --port 8000
"""

import asyncio
import fcntl
import json
import os
import pty
import signal
import struct
import sys
import termios
from typing import Optional

from fastapi import FastAPI, WebSocket, WebSocketDisconnect
from fastapi.responses import HTMLResponse
import uvicorn

# ----------------------------------------------------------------------
# HTML page with xterm.js
# ----------------------------------------------------------------------
HTML_PAGE = """
&lt;!DOCTYPE html&gt;
&lt;html&gt;
&lt;head&gt;
    &lt;meta charset="UTF-8"&gt;
    &lt;title&gt;Web Terminal&lt;/title&gt;
    &lt;link href="https://cdn.jsdelivr.net/npm/xterm@5.3.0/css/xterm.css" rel="stylesheet" /&gt;
    &lt;style&gt;
        body {
            margin: 0;
            padding: 20px;
            background: #1e1e1e;
        }
        #terminal {
            width: 100%;
            height: calc(100vh - 40px);
        }
        .error {
            color: red;
            font-family: monospace;
            padding: 10px;
            background: #2d2d2d;
            border-radius: 4px;
            margin: 10px;
        }
    &lt;/style&gt;
&lt;/head&gt;
&lt;body&gt;
    &lt;div id="terminal"&gt;&lt;/div&gt;
    &lt;script src="https://cdn.jsdelivr.net/npm/xterm@5.3.0/lib/xterm.js"&gt;&lt;/script&gt;
    &lt;script&gt;
        const term = new Terminal({
            cursorBlink: true,
            fontSize: 14,
            fontFamily: 'monospace',
            theme: {
                background: '#1e1e1e',
                foreground: '#d4d4d4'
            }
        });
        term.open(document.getElementById('terminal'));
        term.focus();

        const ws = new WebSocket(`ws://${window.location.host}/ws`);
        ws.binaryType = 'arraybuffer';

        ws.onopen = () =&gt; {
            term.clear();
            // Send initial size
            term.onResize(size =&gt; {
                ws.send(JSON.stringify({
                    type: 'resize',
                    cols: size.cols,
                    rows: size.rows
                }));
            });
            term.onData(data =&gt; {
                ws.send(data);
            });
            // Trigger initial resize after a short delay (ensures terminal is ready)
            setTimeout(() =&gt; {
                const size = { cols: term.cols, rows: term.rows };
                ws.send(JSON.stringify({ type: 'resize', cols: size.cols, rows: size.rows }));
            }, 100);
        };

        ws.onmessage = (event) =&gt; {
            if (event.data instanceof ArrayBuffer) {
                const decoder = new TextDecoder('utf-8');
                const text = decoder.decode(event.data);
                term.write(text);
            } else {
                term.write(event.data);
            }
        };

        ws.onclose = () =&gt; {
            term.write('\\r\\n\\x1b[31m[Connection closed]\\x1b[0m\\r\\n');
            term.options.disableStdin = true;
        };

        ws.onerror = (err) =&gt; {
            console.error('WebSocket error:', err);
        };
    &lt;/script&gt;
&lt;/body&gt;
&lt;/html&gt;
"""

# ----------------------------------------------------------------------
# PTY management functions
# ----------------------------------------------------------------------
def create_pty(shell: str = "/bin/bash") -&gt; tuple[int, int]:
    """
    Create a PTY and spawn a shell.
    Returns (master_fd, child_pid).
    """
    master_fd, slave_fd = pty.openpty()

    pid = os.fork()
    if pid == 0:  # Child
        # Replace stdin, stdout, stderr with the slave PTY
        os.setsid()                 # Become session leader
        os.dup2(slave_fd, 0)        # stdin
        os.dup2(slave_fd, 1)        # stdout
        os.dup2(slave_fd, 2)        # stderr
        os.close(master_fd)
        os.close(slave_fd)

        # Make the slave the controlling terminal
        try:
            ttyname = os.ttyname(0)
            os.close(0)
            os.open(ttyname, os.O_RDWR)
        except OSError:
            # Fallback: already a terminal
            pass

        # Execute the shell
        os.execvp(shell, [shell])
        # If exec fails, exit
        sys.exit(1)

    # Parent
    os.close(slave_fd)
    return master_fd, pid


def set_pty_size(master_fd: int, cols: int, rows: int) -&gt; None:
    """Set the terminal window size of the PTY."""
    winsize = struct.pack("HHHH", rows, cols, 0, 0)
    fcntl.ioctl(master_fd, termios.TIOCSWINSZ, winsize)


def cleanup_pty(master_fd: int, pid: int, loop: asyncio.AbstractEventLoop) -&gt; None:
    """Close the PTY and kill the shell process."""
    try:
        # Remove the reader from the event loop
        loop.remove_reader(master_fd)
    except Exception:
        pass
    try:
        os.close(master_fd)
    except OSError:
        pass
    try:
        # Terminate the child process if still alive
        os.kill(pid, signal.SIGTERM)
        # Wait for it to exit (non-blocking to avoid deadlock)
        os.waitpid(pid, 0)
    except (OSError, ChildProcessError):
        pass


# ----------------------------------------------------------------------
# FastAPI app
# ----------------------------------------------------------------------
app = FastAPI(title="Web Terminal")

@app.get("/")
async def get_index() -&gt; HTMLResponse:
    """Serve the terminal HTML page."""
    return HTMLResponse(content=HTML_PAGE)


@app.websocket("/ws")
async def websocket_terminal(websocket: WebSocket):
    """WebSocket endpoint for the terminal."""
    await websocket.accept()
    loop = asyncio.get_running_loop()

    # Create PTY and shell
    master_fd, pid = create_pty()

    # Set the PTY master to non-blocking mode
    fl = fcntl.fcntl(master_fd, fcntl.F_GETFL)
    fcntl.fcntl(master_fd, fcntl.F_SETFL, fl | os.O_NONBLOCK)

    # Flag to stop the read loop
    running = True

    async def send_pty_output():
        """Read from PTY and send to WebSocket (non-blocking)."""
        nonlocal running
        try:
            while running:
                try:
                    data = os.read(master_fd, 4096)
                except OSError as e:
                    if e.errno == errno.EAGAIN:
                        # No data available now, wait a bit
                        await asyncio.sleep(0.01)
                        continue
                    raise
                if not data:  # EOF – shell exited
                    running = False
                    await websocket.close()
                    break
                # Send data as binary
                await websocket.send_bytes(data)
        except Exception as e:
            print(f"Error reading PTY: {e}", file=sys.stderr)
            running = False
        finally:
            # Clean up when this task ends
            cleanup_pty(master_fd, pid, loop)

    # Create a task for reading PTY output
    pty_task = asyncio.create_task(send_pty_output())

    # Handle incoming WebSocket messages
    try:
        while running:
            try:
                message = await websocket.receive()
            except WebSocketDisconnect:
                break

            if "bytes" in message:
                # Binary message: write to PTY
                os.write(master_fd, message["bytes"])
            elif "text" in message:
                # Text message: could be JSON resize command
                text = message["text"]
                try:
                    data = json.loads(text)
                    if data.get("type") == "resize":
                        cols = data.get("cols", 80)
                        rows = data.get("rows", 24)
                        set_pty_size(master_fd, cols, rows)
