                    # Not JSON, treat as raw input (shouldn't happen with xterm.js)
                    os.write(master_fd, text.encode("utf-8"))
    except Exception as e:
        print(f"WebSocket error: {e}", file=sys.stderr)
    finally:
        running = False
        # Cancel the PTY reader task and wait for it to finish
        pty_task.cancel()
        try:
            await pty_task
        except asyncio.CancelledError:
            pass
        # Cleanup (already called in send_pty_output, but safe to call again)
        cleanup_pty(master_fd, pid, loop)


# ----------------------------------------------------------------------
# Main entry point (if run directly)
# ----------------------------------------------------------------------
if __name__ == "__main__":
    uvicorn.run(app, host="127.0.0.1", port=8000)



